import{_ as s,o as n,c as e,a2 as t}from"./chunks/framework.Wufm-cgV.js";const g=JSON.parse('{"title":"令牌与团队","description":"API Key 和团队管理","frontmatter":{"title":"令牌与团队","description":"API Key 和团队管理"},"headers":[],"relativePath":"zh/guide/tokens-teams.md","filePath":"zh/guide/tokens-teams.md"}'),i={name:"zh/guide/tokens-teams.md"};function l(o,a,r,p,d,h){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="令牌与团队" tabindex="-1">令牌与团队 <a class="header-anchor" href="#令牌与团队" aria-label="Permalink to &quot;令牌与团队&quot;">​</a></h1><h2 id="api-令牌" tabindex="-1">API 令牌 <a class="header-anchor" href="#api-令牌" aria-label="Permalink to &quot;API 令牌&quot;">​</a></h2><p>令牌是客户端用来认证 wr-proxy 的 API Key，每个令牌可以配置：</p><ul><li><strong>模型白名单</strong> — 限制可用模型</li><li><strong>配额</strong> — Token 使用上限</li><li><strong>速率限制</strong> — 每分钟请求数</li><li><strong>智能降级</strong> — 出错时自动降级到经济型模型</li><li><strong>脱敏</strong> — 开启/关闭 PII 剥离</li></ul><h3 id="创建令牌" tabindex="-1">创建令牌 <a class="header-anchor" href="#创建令牌" aria-label="Permalink to &quot;创建令牌&quot;">​</a></h3><ol><li>进入 <strong>令牌管理</strong> → <strong>+ 创建</strong></li><li>填写名称并关联组织</li><li>设置模型访问权限</li><li>配置配额和速率限制</li><li>开启智能降级（可选）</li></ol><h2 id="组织" tabindex="-1">组织 <a class="header-anchor" href="#组织" aria-label="Permalink to &quot;组织&quot;">​</a></h2><p>组织树支持多层级结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>技术部（公司）</span></span>
<span class="line"><span>├── 后端组</span></span>
<span class="line"><span>└── 前端组</span></span>
<span class="line"><span>AI 实验室（公司）</span></span>
<span class="line"><span>└── LLM Ops</span></span>
<span class="line"><span>产品组（公司）</span></span></code></pre></div><p>每个令牌归属于一个组织，支持按组织的配额追踪和计费报表。</p><h2 id="配额管理" tabindex="-1">配额管理 <a class="header-anchor" href="#配额管理" aria-label="Permalink to &quot;配额管理&quot;">​</a></h2><p>配额按令牌设置：</p><ul><li><strong>总配额</strong> — 最大 Token 消耗量</li><li><strong>已用量</strong> — 自动追踪</li><li><strong>剩余量</strong> — 自动计算</li></ul><p>配额即将耗尽时可触发告警。</p><h2 id="团队成员" tabindex="-1">团队成员 <a class="header-anchor" href="#团队成员" aria-label="Permalink to &quot;团队成员&quot;">​</a></h2><p>每个令牌关联一个成员邮箱。管理员可在计费面板查看每人用量统计。</p>`,16)])])}const u=s(i,[["render",l]]);export{g as __pageData,u as default};
